mapper.select:
select count(1)
from knowledge_document
where deleted = 0
  and knowledge_base_id = #{knowledgeBaseId}
  and directory_id = #{directoryId}
  and file_hash = #{fileHash}

mapper.update:
update knowledge_document
set current_version_id = #{versionId}
where id = #{documentId}
  and deleted = 0

mapper.select:
select id, document_uid, knowledge_base_id, directory_id, name, file_resource_id, current_version_id, (select version_uid from knowledge_document_version where id = knowledge_document.current_version_id) as current_version_uid, file_name, file_ext, file_size, file_hash, parse_status, index_status, review_status, publish_status, chunk_count, error_message, create_time, update_time, create_by, update_by, deleted from knowledge_document where deleted = 0
and knowledge_base_id = #{query.knowledgeBaseId}
and directory_id = #{query.directoryId}
and name like concat('%', #{query.name}, '%')
and parse_status = #{query.parseStatus}
and publish_status = #{query.publishStatus}
order by update_time desc

mapper.update:
update knowledge_document
set parse_status = 'PARSE_CHUNKING',
    error_message = null
where id = #{documentId}
  and current_version_id = #{versionId}
  and deleted = 0

update knowledge_document
set parse_status = 'PROCESS_FAILED',
    error_message = #{errorMessage}
where id = #{documentId}
  and current_version_id = #{versionId}
  and deleted = 0

update knowledge_document
set index_status = 'INDEXED'
where id = #{documentId}
  and current_version_id = #{versionId}
  and deleted = 0

update knowledge_document
set review_status = #{reviewStatus}
where id = #{documentId}
  and deleted = 0

update knowledge_document
set publish_status = #{publishStatus}
where id = #{documentId}
  and deleted = 0

mapper.select:
select count(1)
from knowledge_document
where deleted = 0

    and parse_status = #{parseStatus}


    and review_status = #{reviewStatus}


    and publish_status = #{publishStatus}

select id, document_uid, knowledge_base_id, directory_id, name, file_resource_id, current_version_id, (select version_uid from knowledge_document_version where id = knowledge_document.current_version_id) as current_version_uid, file_name, file_ext, file_size, file_hash, parse_status, index_status, review_status, publish_status, chunk_count, error_message, create_time, update_time, create_by, update_by, deleted from knowledge_document where deleted = 0 and ( parse_status = 'PROCESS_FAILED' or review_status = 'WAIT_AUDIT' or review_status = 'AUDIT_PASSED' or parse_status in ('UPLOADED', 'PARSE_CHUNKING') )
and name like concat('%', #{query.documentName}, '%')
and parse_status = #{query.parseStatus}
and review_status = #{query.reviewStatus}
and publish_status = #{query.publishStatus}
and create_time >= #{query.createStartTime}
and create_time <= #{query.createEndTime}
order by case when parse_status = 'PROCESS_FAILED' then 1 when review_status = 'WAIT_AUDIT' then 2 when review_status = 'AUDIT_PASSED' then 3 else 4 end, update_time desc
